+                if (self.isZig()) {
+                    try self.write("    { const val = { sp -= 1; const v = stack[@intCast(sp)]; v; }; qjs.JS_FreeValue(ctx, val); }\n");
+                } else {
+                    try self.write("    FROZEN_FREE(ctx, POP());\n");
+                }
+            },
